// ── Scan-to-activation matching engine ────────────────────────────
// Takes scan result and returns best-matched activations
export function matchActivationsToScan(scanData: {
  dominantDosha?: string;
  activatedNadi?: string;
  priorityChakra?: string;
  lowCoherenceItems?: string[];
  emotionalField?: string;
  organField?: string;
  heartRate?: number;
  hrv?: number;
}, maxResults = 10): BioenergticActivation[] {
  const dosha = scanData.dominantDosha || 'Vata';
  const nadi = scanData.activatedNadi || 'Sushumna';
  const chakra = scanData.priorityChakra || 'Anahata';

  const scored = BIOENERGETIC_LIBRARY.map(item => {
    let score = Math.random() * 5; // small base variation

    // Dosha match
    if (item.dosha.includes(dosha)) score += 30;

    // Chakra match
    if (item.chakra === chakra) score += 25;

    // Nadi-specific boosts
    if (nadi === 'Ida') {
      // Ida = parasympathetic excess = need Pingala/solar activators
      if (['Adaptogen', 'Metabolic', 'Stimulant', 'B Vitamin'].includes(item.category)) score += 15;
    } else if (nadi === 'Pingala') {
      // Pingala = sympathetic excess = need calming/cooling
      if (['Anti-inflammatory', 'Nootropic', 'Antioxidant', 'Bach Flower'].includes(item.category)) score += 15;
    } else if (nadi === 'Blocked') {
      // Blocked = need detox and movement
      if (['Detox', 'Enzyme', 'Probiotic', 'Herb'].includes(item.category)) score += 20;
    } else if (nadi === 'Sushumna') {
      // Central = need balance and longevity
      if (['Longevity', 'Adaptogen', 'Superfood', 'Mushroom'].includes(item.category)) score += 15;
    }

    // Low HRV = nervous system support
    if (scanData.hrv && scanData.hrv < 25) {
      if (['Amino Acid', 'Mineral', 'B Vitamin', 'Adaptogen'].includes(item.category)) score += 10;
    }

    // High HR = anti-inflammatory / calming
    if (scanData.heartRate && scanData.heartRate > 85) {
      if (['Anti-inflammatory', 'Antioxidant', 'Omega-3'].includes(item.category)) score += 10;
    }

    // Emotional field matches
    if (scanData.emotionalField) {
      const ef = scanData.emotionalField.toLowerCase();
      if (ef.includes('grief') || ef.includes('fear')) {
        if (['Bach Flower', 'Adaptogen', 'Amino Acid'].includes(item.category)) score += 12;
      }
      if (ef.includes('anger') || ef.includes('anxiety')) {
        if (['Anti-inflammatory', 'Herb', 'Nootropic'].includes(item.category)) score += 12;
      }
    }

    // Organ field matches
    if (scanData.organField) {
      const of_lower = scanData.organField.toLowerCase();
      if (of_lower.includes('liver')) {
        if (item.name.toLowerCase().includes('liver') || 
            item.name.toLowerCase().includes('milk thistle') ||
            item.name.toLowerCase().includes('dandelion')) score += 20;
      }
      if (of_lower.includes('heart')) {
        if (['Omega-3', 'Antioxidant', 'Mineral'].includes(item.category)) score += 15;
      }
      if (of_lower.includes('brain') || of_lower.includes('nervous')) {
        if (['Nootropic', 'Amino Acid', 'Omega-3', 'B Vitamin'].includes(item.category)) score += 15;
      }
      if (of_lower.includes('gut') || of_lower.includes('digest')) {
        if (['Probiotic', 'Enzyme', 'Prebiotic', 'Herb'].includes(item.category)) score += 15;
      }
    }

    return { ...item, score };
  });

  return (scored as any[])
    .sort((a, b) => b.score - a.score)
    .slice(0, maxResults)
    .map(({ score, ...item }) => item);
}

// ── Quick lookup by category ───────────────────────────────────────
export function getActivationsByCategory(category: string): BioenergticActivation[] {
  return BIOENERGETIC_LIBRARY.filter(a => a.category === category);
}

// ── Search by name ─────────────────────────────────────────────────
export function searchActivations(query: string): BioenergticActivation[] {
  const q = query.toLowerCase();
  return BIOENERGETIC_LIBRARY.filter(a =>
    a.name.toLowerCase().includes(q) ||
    a.sacredName.toLowerCase().includes(q) ||
    a.category.toLowerCase().includes(q) ||
    a.keywords.some((k) => k.toLowerCase().includes(q))
  ).slice(0, 120);
}
